public class Animal {
    String name;
    int age;

    public Animal(String name, int age) {
        this.name = name;
        this.age = age;
        System.out.println("Animal constructor: " + name);
    }

    public void speak() {
        System.out.println(name + " makes a sound.");
    }

    public void describe() {
        System.out.println("Name: " + name + ", Age: " + age);
    }
}

public class Dog extends Animal {
    String breed;

    public Dog(String name, int age, String breed) {
        super(name, age);   // MUST be first statement
        this.breed = breed;
        System.out.println("Dog constructor: " + breed);
    }

    @Override
    public void speak() {              // overrides Animal.speak()
        System.out.println(name + " barks!");
    }

    public void fetch() {
        System.out.println(name + " fetches the ball.");
    }
}

public class Parent {
    public void instanceMethod() {
        System.out.println("Parent instance");
    }
    public static void staticMethod() {
        System.out.println("Parent static");
    }
}

public class Child extends Parent {
    @Override
    public void instanceMethod() {         // OVERRIDE
        System.out.println("Child instance");
    }
    public static void staticMethod() {    // HIDE (not override)
        System.out.println("Child static");
    }
}

public class Demo {
    public static void main(String[] args) {
        Parent ref = new Child();          // declared=Parent, actual=Child
        ref.instanceMethod();              // → "Child instance"  (dynamic dispatch)
        ref.staticMethod();               // → "Parent static"   (compile-time type)
    }
}

public class Shape {
    String color;
    public Shape(String color) {
        this.color = color;
    }
    public String describe() {
        return "Shape[" + color + "]";
    }
}

public class Circle extends Shape {
    double radius;
    public Circle(String color, double radius) {
        super(color);           // call Shape(color)
        this.radius = radius;
    }
    @Override
    public String describe() {
        return super.describe() + "+Circle[r=" + radius + "]";
    }
    public static void main(String[] args) {
        Circle c = new Circle("red", 5.0);
        System.out.println(c.describe());
        // Output: Shape[red]+Circle[r=5.0]
    }
}

