// Design the following class hierarchy:
// Animal (name, sound) → makeSound() prints "[name] says [sound]"
// Pet extends Animal (owner) → describe() prints "[name] owned by [owner]"
// Dog extends Pet (breed) → override makeSound() to print "[name] barks!"
//                          and add fetch() that prints "[name] fetches!"
//
// In main():
//   Create Dog("Rex", "Woof", "Alice", "Labrador")
//   Call makeSound(), describe(), fetch()
//   Also call Animal's makeSound via super reference
//
// Expected output:
//   Rex barks!
//   Rex owned by Alice
//   Rex fetches!
//   Rex says Woof

sections.solution:
public class Animal {
    String name, sound;
    public Animal(String name, String sound) {
        this.name = name;
        this.sound = sound;
    }
    public void makeSound() {
        System.out.println(name + " says " + sound);
    }
}

public class Pet extends Animal {
    String owner;
    public Pet(String name, String sound, String owner) {
        super(name, sound);
        this.owner = owner;
    }
    public void describe() {
        System.out.println(name + " owned by " + owner);
    }
}

public class Dog extends Pet {
    String breed;
    public Dog(String name, String sound, String owner, String breed) {
        super(name, sound, owner);
        this.breed = breed;
    }
    @Override
    public void makeSound() {
        System.out.println(name + " barks!");
    }
    public void fetch() {
        System.out.println(name + " fetches!");
    }
    public static void main(String[] args) {
        Dog d = new Dog("Rex", "Woof", "Alice", "Labrador");
        d.makeSound();          // Rex barks!
        d.describe();           // Rex owned by Alice
        d.fetch();              // Rex fetches!
        // call original Animal makeSound via super
        Animal a = d;           // upcasting
        // dynamic dispatch still calls Dog.makeSound!
        // to call Animal.makeSound directly from Dog:
        // can do from inside Dog: super.makeSound()
        // From outside, demonstrate with a plain Animal object:
        Animal base = new Animal("Rex", "Woof");
        base.makeSound();       // Rex says Woof
    }
}
